UPDATE plate_whitelist
plate_number = #{plateNumber}, owner_id = #{ownerId}, space_id = #{spaceId}, is_active = #{isActive},
WHERE id = #{id}

mapper.select:
SELECT pw.id, pw.plate_number AS plateNumber, pw.owner_id AS ownerId, pw.space_id AS spaceId, pw.is_active AS isActive, o.name AS ownerName, o.phone AS ownerPhone, ps.space_code AS spaceCode, ps.status AS spaceStatus FROM plate_whitelist pw LEFT JOIN owner o ON pw.owner_id = o.id LEFT JOIN parking_space ps ON pw.space_id = ps.id
AND pw.plate_number = #{plateNumber}
ORDER BY pw.create_time DESC
